 674→function movePiece(fromRow, fromCol, toRow, toCol, moveInfo) {
 675→  const piece = boardState[fromRow][fromCol];
 676→
 677→  // Track hasMoved for castling eligibility
 678→  if (piece.type === 'king') {
 679→    if (piece.color === 'white') hasMoved.whiteKing = true;
 680→    else hasMoved.blackKing = true;
 681→  }
 682→  if (piece.type === 'rook') {
 683→    if (piece.color === 'white') {
 684→      if (fromRow === 7 && fromCol === 0) hasMoved.whiteRookA = true;
 685→      if (fromRow === 7 && fromCol === 7) hasMoved.whiteRookH = true;
 686→    } else {
 687→      if (fromRow === 0 && fromCol === 0) hasMoved.blackRookA = true;
 688→      if (fromRow === 0 && fromCol === 7) hasMoved.blackRookH = true;
 689→    }
 690→  }
 691→
 692→  // Handle captures (including marking captured rooks)
 693→  const captured = boardState[toRow][toCol];
 694→  if (captured) {
 695→    if (captured.type === 'rook') {
 696→      if (toRow === 7 && toCol === 0) hasMoved.whiteRookA = true;
 697→      if (toRow === 7 && toCol === 7) hasMoved.whiteRookH = true;
 698→      if (toRow === 0 && toCol === 0) hasMoved.blackRookA = true;
 699→      if (toRow === 0 && toCol === 7) hasMoved.blackRookH = true;
 700→    }
 701→    if (captured.color === 'white') {
 702→      capturedBlack.push(captured);
 703→    } else {
 704→      capturedWhite.push(captured);
 705→    }
 706→    updateCaptured();
 707→  }
 708→
 709→  // Handle en passant capture
 710→  if (moveInfo && moveInfo.enPassant) {
 711→    const epPawn = boardState[fromRow][toCol];
 712→    if (epPawn) {
 713→      if (epPawn.color === 'white') capturedBlack.push(epPawn);
 714→      else capturedWhite.push(epPawn);
 715→      updateCaptured();
 716→    }
 717→    boardState[fromRow][toCol] = null;
 718→    setPieceEl(fromRow, toCol);
 719→  }
 720→
 721→  // Record last move for en passant detection
 722→  lastMove = { piece: { ...piece }, fromRow, fromCol, toRow, toCol };
 723→
 724→  // Execute move
 725→  boardState[toRow][toCol] = piece;
 726→  boardState[fromRow][fromCol] = null;
 727→
 728→  // Handle castling rook movement
 729→  if (moveInfo && moveInfo.castling) {
 730→    const baseRow = toRow;
 731→    if (moveInfo.castling === 'kingside') {
 732→      boardState[baseRow][5] = boardState[baseRow][7];
 733→      boardState[baseRow][7] = null;
 734→      setPieceEl(baseRow, 7);
 735→      setPieceEl(baseRow, 5);
 736→    } else {
 737→      boardState[baseRow][3] = boardState[baseRow][0];
 738→      boardState[baseRow][0] = null;
 739→      setPieceEl(baseRow, 0);
 740→      setPieceEl(baseRow, 3);
 741→    }
 742→  }
 743→
 744→  // Update DOM
 745→  setPieceEl(fromRow, fromCol);
 746→  setPieceEl(toRow, toCol);
 747→
 748→  highlightLastMove();
 749→
 750→  // Check for pawn promotion
 751→  const promoRow = piece.color === 'white' ? 0 : 7;
 752→  if (piece.type === 'pawn' && toRow === promoRow) {
 753→    pendingPromotion = { row: toRow, col: toCol };
 754→    showPromotionDialog(piece.color);
 755→    return; // Don't switch turn yet
 756→  }
 757→
 758→  finishTurn();
 759→}
