 958→function getPstValue(type, color, row, col) {
 959→  const table = PST[type];
 960→  if (!table) return 0;
 961→  // White pieces use the table as-is; black pieces mirror vertically
 962→  const r = color === 'white' ? row : 7 - row;
 963→  return table[r][col];
 964→}
 965→
 966→function evaluateBoard() {
 967→  let score = 0;
 968→  for (let r = 0; r < 8; r++) {
 969→    for (let c = 0; c < 8; c++) {
 970→      const p = boardState[r][c];
 971→      if (!p) continue;
 972→      const material = AI_PIECE_VALUES[p.type];
 973→      const positional = getPstValue(p.type, p.color, r, c);
 974→      const value = material + positional;
 975→      score += p.color === 'white' ? value : -value;
 976→    }
 977→  }
 978→  return score;
 979→}
 980→
 981→// Generate all legal moves for a given color in the current boardState.
 982→// Each move is { fromRow, fromCol, toRow, toCol, enPassant?, castling? }
 983→function generateAllLegalMoves(color) {
 984→  const moves = [];
 985→  for (let r = 0; r < 8; r++) {
 986→    for (let c = 0; c < 8; c++) {
 987→      const p = boardState[r][c];
 988→      if (!p || p.color !== color) continue;
 989→      const legal = getLegalMoves(p, r, c);
 990→      for (const m of legal) {
 991→        moves.push({ fromRow: r, fromCol: c, toRow: m.row, toCol: m.col, enPassant: m.enPassant, castling: m.castling });
 992→      }
 993→    }
 994→  }
 995→  return moves;
 996→}
