 998→// Apply a move on boardState, returning an undo object to restore later.
 999→// Handles captures, en passant, castling, and auto-queen promotion.
1000→function applyMove(move) {
1001→  const { fromRow, fromCol, toRow, toCol } = move;
1002→  const piece = boardState[fromRow][fromCol];
1003→  const undo = {
1004→    fromRow, fromCol, toRow, toCol,
1005→    piece,
1006→    captured: boardState[toRow][toCol],
1007→    lastMove,
1008→    hasMoved: { ...hasMoved },
1009→    epCaptured: null,
1010→    castlingRook: null,
1011→    promoted: false,
1012→    originalPiece: null,
1013→  };
1014→
1015→  // Track king/rook moves for castling
1016→  if (piece.type === 'king') {
1017→    if (piece.color === 'white') hasMoved.whiteKing = true;
1018→    else hasMoved.blackKing = true;
1019→  }
1020→  if (piece.type === 'rook') {
1021→    if (piece.color === 'white') {
1022→      if (fromRow === 7 && fromCol === 0) hasMoved.whiteRookA = true;
1023→      if (fromRow === 7 && fromCol === 7) hasMoved.whiteRookH = true;
1024→    } else {
1025→      if (fromRow === 0 && fromCol === 0) hasMoved.blackRookA = true;
1026→      if (fromRow === 0 && fromCol === 7) hasMoved.blackRookH = true;
1027→    }
1028→  }
1029→  // Mark captured rooks
1030→  const cap = boardState[toRow][toCol];
1031→  if (cap && cap.type === 'rook') {
1032→    if (toRow === 7 && toCol === 0) hasMoved.whiteRookA = true;
1033→    if (toRow === 7 && toCol === 7) hasMoved.whiteRookH = true;
1034→    if (toRow === 0 && toCol === 0) hasMoved.blackRookA = true;
1035→    if (toRow === 0 && toCol === 7) hasMoved.blackRookH = true;
1036→  }
1037→
1038→  // En passant capture
1039→  if (move.enPassant) {
1040→    undo.epCaptured = boardState[fromRow][toCol];
1041→    boardState[fromRow][toCol] = null;
1042→  }
1043→
1044→  // Execute move
1045→  boardState[toRow][toCol] = piece;
1046→  boardState[fromRow][fromCol] = null;
1047→
1048→  // Castling rook movement
1049→  if (move.castling) {
1050→    const baseRow = toRow;
1051→    if (move.castling === 'kingside') {
1052→      undo.castlingRook = { rook: boardState[baseRow][7], fromC: 7, toC: 5 };
1053→      boardState[baseRow][5] = boardState[baseRow][7];
1054→      boardState[baseRow][7] = null;
1055→    } else {
1056→      undo.castlingRook = { rook: boardState[baseRow][0], fromC: 0, toC: 3 };
1057→      boardState[baseRow][3] = boardState[baseRow][0];
1058→      boardState[baseRow][0] = null;
1059→    }
1060→  }
1061→
1062→  // Pawn promotion — always promote to queen for AI
1063→  const promoRow = piece.color === 'white' ? 0 : 7;
1064→  if (piece.type === 'pawn' && toRow === promoRow) {
1065→    undo.promoted = true;
1066→    undo.originalPiece = piece;
1067→    const queenKey = piece.color === 'white' ? 'Q' : 'q';
1068→    boardState[toRow][toCol] = makePiece(queenKey);
1069→  }
1070→
1071→  // Update lastMove for en passant detection in deeper searches
1072→  lastMove = { piece: { ...piece }, fromRow, fromCol, toRow, toCol };
1073→
1074→  return undo;
1075→}
1076→
1077→function undoMove(undo) {
1078→  const { fromRow, fromCol, toRow, toCol } = undo;
1079→
1080→  // Restore the piece (use original if it was promoted)
1081→  boardState[fromRow][fromCol] = undo.promoted ? undo.originalPiece : boardState[toRow][toCol];
1082→  boardState[toRow][toCol] = undo.captured;
1083→
1084→  // Undo en passant capture
1085→  if (undo.epCaptured) {
1086→    boardState[fromRow][toCol] = undo.epCaptured;
1087→  }
1088→
1089→  // Undo castling rook
1090→  if (undo.castlingRook) {
1091→    const cr = undo.castlingRook;
1092→    boardState[toRow][cr.fromC] = boardState[toRow][cr.toC];
1093→    boardState[toRow][cr.toC] = null;
1094→  }
1095→
1096→  // Restore game state
1097→  lastMove = undo.lastMove;
1098→  hasMoved = undo.hasMoved;
1099→}
1100→
1101→// Minimax search (no alpha-beta pruning).
1102→// Returns the evaluation score from the perspective of the maximising player (white).
1103→// depth: remaining depth to search
1104→// isMaximising: true when it's white's turn to move
1105→function minimax(depth, isMaximising) {
1106→  if (depth === 0) {
1107→    return evaluateBoard();
1108→  }
1109→
1110→  const color = isMaximising ? 'white' : 'black';
1111→  const moves = generateAllLegalMoves(color);
1112→
1113→  // No legal moves: checkmate or stalemate
1114→  if (moves.length === 0) {
1115→    if (isKingInCheck(color, boardState)) {
1116→      // Checkmate — very bad for the side to move
1117→      return isMaximising ? -Infinity : Infinity;
1118→    }
1119→    return 0; // Stalemate
1120→  }
1121→
1122→  if (isMaximising) {
